int findMostBookedRoom(int totalRooms, int meetings[][2], int mSize) {
    int roomCount[totalRooms];
    for (int i = 0; i < totalRooms; i++) {
        roomCount[i] = 0;
    }

    int freeRooms[totalRooms];
    for (int i = 0; i < totalRooms; i++) {
        freeRooms[i] = i;
    }

    int busyRooms[mSize][2];
    int busySize = 0;

    for (int i = 0; i < mSize; i++) {
        int start = meetings[i][0];
        int end = meetings[i][1];
        int duration = end - start;

        // Free rooms that are available by start time
        for (int j = 0; j < totalRooms; j++) {
            if (freeRooms[j] != -1) {
                // Assign meeting to free room
                roomCount[freeRooms[j]]++;
                freeRooms[j] = -1;
                busyRooms[busySize][0] = end;
                busyRooms[busySize][1] = freeRooms[j];
                busySize++;
                break;
            }
        }

        // If no free rooms, delay meeting until a room becomes available
        if (busySize > 0) {
            int earliest = 0;
            for (int j = 1; j < busySize; j++) {
                if (busyRooms[j][0] < busyRooms[earliest][0]) {
                    earliest = j;
                }
            }
            roomCount[busyRooms[earliest][1]]++;
            busyRooms[earliest][0] += duration;
        }
    }

    int maxRoom = 0;
    for (int i = 1; i < totalRooms; i++) {
        if (roomCount[i] > roomCount[maxRoom]) {
            maxRoom = i;
        }
    }
    return maxRoom;
}

