using namespace std;

int findMostBookedRoom(int totalRooms, vector<vector<int>>& meetings) {
    priority_queue<int, vector<int>, greater<int>> freeRooms;
    for (int i = 0; i < totalRooms; i++) {
        freeRooms.push(i);
    }

    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> busyRooms;

    vector<int> roomCount(totalRooms, 0);

    for (auto& meeting : meetings) {
        int start = meeting[0];
        int end = meeting[1];
        int duration = end - start;

        // Free rooms that are available by start time
        while (!busyRooms.empty() && busyRooms.top().first <= start) {
            freeRooms.push(busyRooms.top().second);
            busyRooms.pop();
        }

        if (!freeRooms.empty()) {
            int room = freeRooms.top();
            freeRooms.pop();
            busyRooms.push({end, room});
            roomCount[room]++;
        } else {
            auto earliest = busyRooms.top();
            busyRooms.pop();
            busyRooms.push({earliest.first + duration, earliest.second});
            roomCount[earliest.second]++;
        }
    }

    int maxRoom = 0;
    for (int i = 1; i < totalRooms; i++) {
        if (roomCount[i] > roomCount[maxRoom]) {
            maxRoom = i;
        }
    }
    return maxRoom;
}

