import java.util.PriorityQueue;
import java.util.Scanner;
public class Main {
    public static int findMostBookedRoom(int totalRooms, int[][] meetings) {
        PriorityQueue<Integer> freeRooms = new PriorityQueue<>();
        for (int i = 0; i < totalRooms; i++) {
            freeRooms.offer(i);
        }

        PriorityQueue<int[]> busyRooms = new PriorityQueue<>((a, b) -> a[0] - b[0]);

        int[] roomCount = new int[totalRooms];

        for (int[] meeting : meetings) {
            int start = meeting[0];
            int end = meeting[1];
            int duration = end - start;

            // Free rooms that are available by start time
            while (!busyRooms.isEmpty() && busyRooms.peek()[0] <= start) {
                freeRooms.offer(busyRooms.poll()[1]);
            }

            if (!freeRooms.isEmpty()) {
                int room = freeRooms.poll();
                busyRooms.offer(new int[]{end, room});
                roomCount[room]++;
            } else {
                int[] earliest = busyRooms.poll();
                busyRooms.offer(new int[]{earliest[0] + duration, earliest[1]});
                roomCount[earliest[1]]++;
            }
        }

        int maxRoom = 0;
        for (int i = 1; i < totalRooms; i++) {
            if (roomCount[i] > roomCount[maxRoom]) {
                maxRoom = i;
            }
        }
        return maxRoom;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int totalRooms = scanner.nextInt();
            int mSize = scanner.nextInt();
            int[][] meetings = new int[mSize][2];
            for (int i = 0; i < mSize; i++) {
                meetings[i][0] = scanner.nextInt();
                meetings[i][1] = scanner.nextInt();
            }
            System.out.println(findMostBookedRoom(totalRooms, meetings));
        }
    }
}

