            let [freeTime, room] = busyRooms.shift();
            busyRooms.push([freeTime + duration, room]);
            busyRooms.sort((a, b) => a[0] - b[0]);
            roomCount[room]++;
        }
    }

    let maxRoom = 0;
    for (let i = 1; i < totalRooms; i++) {
